System.register([],function(e,n){var t,c,o,i,a;return{setters:[],execute:function(){c=(e,n,t,c,o,i)=>({id:e,type:"dialogue",speaker:n,speakerKey:t,text:c,sprite:o?{key:o,position:"linmo"===o?"left":"right"}:void 0,effects:i}),o=(e,n,t)=>({id:e,type:"choice",text:n,choices:t,speaker:""}),i=(e,n,t,c,o)=>({id:e,type:"quiz",text:n,quiz:t,onCorrect:c,onWrong:o,speaker:""}),a=(e,n)=>({id:e,type:"system",text:n,speaker:""}),e("chapter1Script",[(t=(e,n,t)=>({id:e,type:"narration",text:n,speaker:"",background:t}))("ch1-0-0",'第1章：蛋白质折叠异常事件\n\n第二次"第一天"。走廊和昨天一模一样。\n但这次——你注意到了上次忽略的东西。',"corridor"),c("ch1-0-1","老周","oldzhou","那边别去。B区——","oldzhou"),t("ch1-0-2",'"地下层。上个月有个研究员下去取样，回来不对劲了。离心机三号有异响。"\n你替他说完了后面的话。',"corridor"),c("ch1-0-3","老周","oldzhou","……你第一次来，怎么知道我要说什么？\n算了。可能是我记错了。年纪大了。","oldzhou"),t("ch1-0-4",'因为他已经说过一次了。在你死掉的那个"昨天"里。',"corridor"),t("ch1-1-0","办公区。林雪正在从泡沫箱中取出冻干蛋白样品。","office"),c("ch1-1-1","林雪","linxue","林墨。既然来了，今天跟我学蛋白质纯化。\n你知道为什么蛋白纯化是所有生化实验的基础吗？","linxue"),i("ch1-1-2","她从实验台下拿出一个泡沫箱，干冰的白色冷气从中溢出。",{question:"在重组蛋白纯化中，Ni-NTA亲和层析的原理是什么？",options:[{label:"A",text:"利用蛋白的电荷差异分离",correct:!1},{label:"B",text:"利用组氨酸标签(His-tag)与镍离子(Ni²⁺)的配位结合",correct:!0},{label:"C",text:"利用蛋白分子量差异分离",correct:!1},{label:"D",text:"利用蛋白的疏水性差异分离",correct:!1}],explanation:"His-tag是6-10个连续组氨酸组成的短肽标签。组氨酸侧链的咪唑基团能与Ni²⁺形成稳定的配位键，使目标蛋白被树脂吸附。用含高浓度咪唑(通常250-500mM)的缓冲液竞争洗脱即可获得纯化蛋白。",knowledgeId:"ni_nta_affinity",knowledgeTitle:"Ni-NTA亲和层析——重组蛋白纯化的核心技术"},[c("ch1-1-2c","林雪","linxue","……还不错。来吧，带你看个东西。","linxue",{affection:{linxue:5}})],[c("ch1-1-2w","林雪","linxue","回去看蛋白纯化的章节。这是基础中的基础。","linxue")]),t("ch1-2-0","B1核心实验室。大型发酵罐发出低沉的嗡鸣。淡绿色的培养液在罐中缓缓旋转。","b1_lab"),c("ch1-2-1","林雪","linxue","这是我们公司最核心的项目——Recombinant QZ-1。一种从极端嗜热古菌中克隆的重组蛋白。\n我们通过分子伴侣GroEL/GroES共表达系统来帮助它正确折叠。","linxue"),i("ch1-2-2","林雪指着屏幕上旋转的蛋白质3D结构图。",{question:"分子伴侣(molecular chaperone)的作用机制是什么？",options:[{label:"A",text:"催化肽键的形成",correct:!1},{label:"B",text:"为新合成或应激变性的多肽链提供正确折叠所需的隔离微环境，防止错误折叠和疏水聚集",correct:!0},{label:"C",text:"切除信号肽",correct:!1},{label:"D",text:"将蛋白运输到细胞外",correct:!1}],explanation:'分子伴侣不提供折叠信息——蛋白的折叠信息已包含在一级结构中(Anfinsen实验)。分子伴侣通过提供隔离环境(GroEL/GroES笼)，防止新生肽链在拥挤的细胞质中发生非特异性疏水聚集。1972年诺贝尔化学奖授予Christian Anfinsen——他的核糖核酸酶变性-复性实验证明了"一级结构决定高级结构"。',knowledgeId:"molecular_chaperone",knowledgeTitle:"分子伴侣与Anfinsen实验——蛋白质折叠的核心机制"},[c("ch1-2-2c","林雪","linxue","你知道Anfinsen实验……你的生化基础比大多数实习生好。","linxue",{affection:{linxue:8}})],[c("ch1-2-2w","林雪","linxue","Anfinsen——1972年诺贝尔化学奖。用8M尿素变性核糖核酸酶——透析去除变性剂——蛋白自发复性。证明了折叠信息在序列里。\n记住这个名字。他是我爸最崇拜的科学家。","linxue")]),c("ch1-2-3","林雪","linxue","QZ-1很特殊。它的体外复性条件极其苛刻——pH6.8、温度37°C、需要特定的氧化还原电位来形成正确的二硫键配对。\n而且——它有一个奇怪的性质。","linxue"),c("ch1-2-4","林雪","linxue",'它在与特定DNA序列结合后——会发生别构效应。\n就像——它在"识别"什么。',"linxue"),t("ch1-2-5","特定DNA序列。你莫名地想起了自己的基因检测报告——前公司的入职体检时做过全基因组测序。报告中有一条注释——MT-ND5基因存在罕见非同义突变，临床意义未明。","b1_lab"),t("ch1-3-0","走廊。DNA存储库的门——虚掩着。里面透出微弱的蓝光。","dna_storage"),o("ch1-3-1","你路过DNA存储库时，发现门没关严。里面有人。",[{text:"【悄悄靠近查看】冒着被发现的风险一探究竟",next:[t("ch1-3-2a","通过门缝——苏菲亚正在用微型相机拍摄低温冰箱里的样品管编号。她的手边——是那支看起来像口红的微型录音器。","dna_storage"),c("ch1-3-3a","苏菲亚","sophia","（接电话，声音轻得几乎听不到）Emma？宝贝？妈妈在上班……嗯，我知道，我也想你。","sophia"),t("ch1-3-4a",'她挂了电话。在冷柜的蓝光中——她脸上有泪水。\n"再坚持一下，宝贝……妈妈很快就能拿到酶了……"',"dna_storage"),t("ch1-3-5a","Emma。她有一个女儿。需要酶？\nQZ-酶能治疗什么疾病吗？——如果她在知识库中记录了线粒体DNA突变的相关知识——线粒体遗传病？Leigh综合征？","dna_storage")],effects:{flag:"discovered_sophia_secret",affection:{sophia:5}}},{text:"【假装没看到离开】暂时不打草惊蛇",next:[t("ch1-3-2b","你轻手轻脚地走开了。但现在你知道了——苏菲亚有问题。下次——你会更注意她的动向。","corridor")]}]),t("ch1-4-0",'傍晚。6点40分。十分钟后——如果什么都不做——发酵罐会爆炸。\n但你这次——可以利用"记忆"来干预。',"b1_lab"),t("ch1-4-1","你走到控制台前。发酵罐的实时数据——pH从6.8漂移到5.2，温度从37°C升到42°C。\n上次你死在这些数据下。这次——你回来了。","b1_lab"),i("ch1-4-2","你分析着异常数据：发酵罐中的重组QZ-1蛋白在pH5.2、42°C的条件下——",{question:"发酵罐中pH从6.8漂移到5.2，温度从37°C升到42°C——QZ-1蛋白会发生什么？",options:[{label:"A",text:"会更稳定——高温加速折叠",correct:!1},{label:"B",text:"会发生不可逆变性和聚集——pH变化破坏离子键，高温破坏氢键和疏水作用",correct:!0},{label:"C",text:"会提高酶活性",correct:!1},{label:"D",text:"会自行复性恢复活性",correct:!1}],explanation:"绝大多数蛋白在偏离最适pH和温度时会发生变性：pH变化改变氨基酸侧链质子化状态→破坏维持三级结构的离子键；高温破坏维持构象的氢键和疏水作用→疏水核心暴露→无定形聚集。蛋白质变性后：溶解度↓、粘度↑、生物活性丧失、易被蛋白酶水解。但一级结构（肽键）不受影响。",knowledgeId:"protein_denaturation",knowledgeTitle:"蛋白质变性的条件与后果"},[t("ch1-4-2c","你确认了——上次就是这些条件导致了死亡。这次——你必须阻止。但时间只剩6分钟。你不可能同时通知所有人。\n你只能找一个人。","b1_lab")],[t("ch1-4-2w","你不太确定——但数据不会说谎。pH和温度都在偏离最适条件。不管会不会变性——你都必须行动。","b1_lab")]),o("ch1-4-3","⭐ 关键抉择 ⭐\n\n时间只剩6分钟。你只能找一个人帮助。\n这个人——将决定你接下来要走的路。",[{text:'【去找林雪】"发酵罐pH异常，你的重组蛋白正在变性"',next:[c("ch1-4-lx","林雪","linxue","你怎么知道QZ-1的最适pH是6.8？我没告诉过你。……不过——数据是对的。\n帮我关掉加热器。我调整pH。快！","linxue",{affection:{linxue:15}}),t("ch1-4-lx-n","林雪在控制面板上飞速操作。她的灰蓝色眼瞳在你的脸上停留了一秒——不是审视——是重新评估。\n> 林雪线已解锁。后续剧情详见林雪线专属剧本。","b1_lab")],effects:{flag:"route_linxue",affection:{linxue:15}}},{text:'【去找陈阳】"帮我关掉3号发酵罐的加热器——温控系统故障了"',next:[c("ch1-4-cy","陈阳","chenyang","温控故障？我就知道那台破罐子迟早出事！\n跟我来——我知道后备电源切断开关在哪——比密码快！","chenyang",{affection:{chenyang:15}}),t("ch1-4-cy-n","陈阳二话不说冲向走廊的配电箱。他的动作出乎意料地敏捷——和平时懒洋洋的样子完全不同。\n> 陈阳线已解锁。后续剧情详见陈阳线专属剧本。","corridor")],effects:{flag:"route_chenyang",affection:{chenyang:15}}},{text:'【去找苏菲亚】"你的微型相机能拍到控制面板上的错误代码吗？"',next:[c("ch1-4-sf","苏菲亚","sophia",'……你知道我在拍什么。\n（她盯着你看了三秒——然后从口袋里拿出那支"口红"）\n微型相机的红外模式——能拍到肉眼看不到的显示屏故障码。跟我来。',"sophia",{affection:{sophia:15}}),t("ch1-4-sf-n","苏菲亚走在前面。你注意到她下意识地摸了一下项链吊坠——像是在寻求力量。\n> 苏菲亚线已解锁。后续剧情详见苏菲亚线专属剧本。","corridor")],effects:{flag:"route_sophia",affection:{sophia:15}},locked:!0,lockedHint:"🔒 通关任意一条路线后解锁"},{text:'【去找小雅】"帮我入侵发酵罐控制系统——用你的生物脑"',next:[c("ch1-4-xy","小雅","xiaoya","入侵？？不——不是入侵——是——绕过防火墙——\n（她闭上眼睛——手指离开键盘——然后在空气中虚敲——）\nB1-3-加热系统……已定位……关闭……完成！","xiaoya",{affection:{xiaoya:15}}),t("ch1-4-xy-n",'小雅睁开眼睛时，一脸困惑地看着自己悬在空中的手指。"咦——我什么时候——"\n> 小雅线已解锁。后续剧情详见小雅线专属剧本。',"office")],effects:{flag:"route_xiaoya",affection:{xiaoya:15}},locked:!0,lockedHint:"🔒 通关两条路线后解锁"},{text:'【去找王博士】"通风系统需要重启——B3层可能出了问题"',next:[c("ch1-4-wb","王博士","wang","……你身上有他的影子。\n（他没有问你怎么知道——只是推了推老花镜）\n跟我来。张总改了我的生物识别权限——但他忘了——密码是存在这里的。","wang",{affection:{wang:15}}),t("ch1-4-wb-n","王博士指了指自己的脑袋。他带你走向VIP电梯——指纹验证失败——他输入了一串手写密码——电梯开了。\n> 王博士线已解锁。后续剧情详见王博士线专属剧本。","corridor")],effects:{flag:"route_wang",affection:{wang:15}},locked:!0,lockedHint:"🔒 通关三条路线后解锁"},{text:"【独自行动】不找任何人——自己想办法关掉发酵罐",next:[t("ch1-4-zz","你没有找任何人。在走廊上，你撞见了张总。他正独自站在茶水间里——手套摘了下来——正在查看自己手上的老年斑。他看到你——没有惊讶——反而像是等了很久。\n> 张总隐藏线已解锁。这条路——没有回头。","breakroom")],effects:{flag:"route_zhang",affection:{zhang:5}},locked:!0,lockedHint:"🔒 通关全部五条路线后解锁"}]),t("ch1-4-end","你做出了选择。警报灯依然在闪烁——但这一次——你不再是新手。\n你知道将要发生什么。你准备好了。","b1_lab"),a("ch1-end",'▎第1章完结：蛋白质折叠异常事件\n\n▎解锁知识条目：Ni-NTA亲和层析 | 分子伴侣与Anfinsen实验 | 蛋白质变性的条件与后果\n\n▎角色线已根据你的选择激活\n▎轮回次数：1 / 最大≈25\n▎第2章预告：DNA样本污染谜案\n\n"有人在DNA存储库里——系统地抹除你的基因痕迹。"')])}}});